// 1. Set the label and value
let topic = env.get("label");
let value = msg.payload;

const useFixed = env.get("use_fixed_value");
if (useFixed) {
    value = env.get("value");
}

// Generate JSON Array for Stored Procedure
let numericValue;

// Normalization: Convert booleans to 1 or 0 (The Stored Procedure expects a number)
if (typeof value === 'boolean') {
    numericValue = value ? 1 : 0;
} else if (typeof value === 'number') {
    numericValue = value;
} else {
    // Handle numeric strings or invalid values (default to 0)
    numericValue = parseFloat(value) || 0;
}

// 2. Package this into a single-element array in the required JSON format
msg.payload = [{
    "label": topic,
    "value": numericValue
}];

// msg.topic is set in the Core HAL, but the existing one gets removed for clarity
delete msg.topic;

return msg;

// 1. Get labels list
const labels = env.get("labels");

if (!Array.isArray(labels) || labels.length === 0) {
    return null;
}

// 2. Get values list
let valuesList;
const useFixed = env.get("use_fixed_values");

if (useFixed) {
    valuesList = env.get("values");
} else {
    valuesList = msg.payload;
}

if (!Array.isArray(valuesList)) {
    // Handle singular value input gracefully by converting to array
    valuesList = [valuesList];
}

// 3. Mapping and JSON construction
const commandArray = labels.map((label, index) => {
    let val = valuesList[index];
    let numericValue;

    // Normalization: Convert booleans to 1 or 0 (The Stored Procedure expects a number)
    if (typeof val === 'boolean') {
        numericValue = val ? 1 : 0;
    } else if (typeof val === 'number') {
        numericValue = val;
    } else {
        numericValue = parseFloat(val) || 0;
    }

    // Construct the object expected by the Stored Procedure
    return {
        "label": label,
        "value": numericValue
    };
});

// 4. Send the array of objects
msg.payload = commandArray;
return msg;

// 1. Configuration
const labels = env.get("labels");

// If the configured list of labels is invalid, stop immediately.
if (!Array.isArray(labels)) return null;

// 2. Process if the incoming message topic is relevant to this node's configuration.
if (labels.includes(msg.topic)) {

    // State Management
    // Safely retrieve the aggregated state object from node context, or initialize as empty object.
    let state = context.get("state") || {};

    // Update the persistent state map with the new value that just arrived.
    state[msg.topic] = msg.payload;
    context.set("state", state);

    // --- OUTPUT GENERATION (WRITE IOS FORMAT) ---

    // Map the configured labels to their current values in strict, defined order.
    // This generates the simple array: [value1, value2, value3...]
    const valuesArray = labels.map(key => {
        const val = state[key];
        // Protection: If a label's value is undefined (not yet read), assume false/0 for safety
        return (val === undefined) ? false : val;
    });

    // The output payload is the ordered array, which is exactly what "Write IOs" expects.
    msg.payload = valuesArray;

    return msg;
}

// Ignore the message if its topic is not in the configured list.
return null;

// Function: function 1
// ----------------------------------------------------------------------
// 1. Input Normalization
let updates = msg.payload;

if (!Array.isArray(updates) || updates.length === 0) {
    return null;
}

// 2. Normalize values (ensure 1/0 for SQL compatibility with net_required_value)
updates = updates.map(u => {
    let val = u.value;
    if (typeof val === 'boolean') val = val ? 1 : 0;
    return { label: u.label, value: val };
});

// 3. Generate cases
let cases = updates.map(u =>
    `WHEN '${u.label}' THEN ${u.value}`
).join(' ');

let labels = updates.map(u => `'${u.label}'`).join(',');

// 4. Build query with safety check (joining with model_io_definition)
msg.topic = `
    UPDATE rtmirror rt
    JOIN module_io_config cfg 
        ON rt.fk_module_id = cfg.fk_module_id 
        AND rt.fk_io_definition_id = cfg.fk_io_definition_id
    JOIN model_io_definition mid
        ON rt.fk_io_definition_id = mid.io_definition_id
    SET rt.net_required_value = CASE cfg.user_label 
        ${cases} 
    END
    WHERE cfg.user_label IN (${labels})
    AND mid.hardware_access = 'readwrite'
`;
msg.payload = [];
return msg;

// Get the rows of the query (an array of objects)
const rows = msg.payload;

// Recover the previous state from the node context
let lastState = context.get('lastState') || {};

// Iterate through each row that the database has returned
rows.forEach(row => {
    let topic = row.user_label;
    let value = row.net_value;
    let payload = value;

    // 1. Normalization (Handle floats from DOUBLE in DB)
    if (row.io_type === 'bit') {
        payload = (value === 1 || value === true || value === 1.0);
    }

    // 2. Unit appending for display
    let displayValue = payload;
    if (row.io_type === 'register' && row.units) {
        displayValue = `${value} ${row.units}`;
    }

    // 3. RBE Logic: Compare current value with last state
    if (lastState[topic] !== payload) {
        node.send({
            topic: topic,
            payload: payload,
            displayValue: displayValue,
            units: row.units,
            purpose: row.purpose
        });
        lastState[topic] = payload;
    }
});

context.set('lastState', lastState);
return null;

// 1. Receive a simple Array [true, false, true...]
const values = msg.payload;

// 2. Check if ALL values are true
let allTrue = true;

// Iterate through the list of values
for (let val of values) {
    // If find one that is NOT strictly true (or 1), fail
    if (val !== true && val !== 1) {
        allTrue = false;
        break;
    }
}

// 3. Output Calculation
const outputValue = allTrue ? 32767 : 0;

// Set the payload with the resulting value (for singular Write IO node)
msg.payload = outputValue;

return msg;

// Read the previous state from the context variable (storage in the node)
let currentState = context.get('valveState') || 0;
let newState = currentState === 0 ? 1 : 0; // Toggle 0 <-> 1

// Save the new state for the next cycle
context.set('valveState', newState);

// The 'Write IO' subflow expects the label and the value.
// We prepare the JSON array that the subflow expects:
msg.payload = newState;

return msg;
